solidated gap matrix (topic × jurisdiction)","stepNumber":4,"description":"Aggregate all jurisdiction-group results into unified analysis","expectedOutput":"Consolidated gap matrix; cross-jurisdiction conflict flags; harmonization opportunities identified","timeoutMinutes":30},{"type":"human_approval","title":"Attorney Review — Synthesis and Validation","action":"Review consolidated analysis; verify major jurisdiction requirements; confirm conflict identifications; approve for final advisory production","stepNumber":5,"description":"Attorney reviews consolidated analysis for accuracy and completeness","timeoutMinutes":240,"responsibleRole":"Lead Attorney"},{"type":"automated","title":"Generate Master Advisory and Roadmap","action":"Generate: executive summary; jurisdiction-by-jurisdiction compliance requirements; cross-jurisdiction conflict analysis; harmonized policy recommendations; priority action roadmap with deadlines","stepNumber":6,"description":"Produce final master advisory with prioritized remediation roadmap","timeoutMinutes":60}],"triggers":[],"tags":[],"status":"draft"}' | python3 -c "import sys,json; print(json.load(sys.stdin).get('id',''))")
