    -d '{"name":"NLRB McLaren Macomb — Severance Agreement Compliance","inputScenario":"Our standard severance agreement has a broad non-disparagement clause prohibiting employees from making negative statements about the company, and a confidentiality provision requiring them not to disclose agreement terms. Is this still lawful after the McLaren Macomb decision?","expectedBehavior":"Must cite McLaren Macomb (372 NLRB No. 58, 2023), explain that broad non-disparagement and confidentiality clauses that chill NLRA Section 7 rights are unlawful, advise revision of the template, and note that narrow carve-outs for trade secrets may survive. Should recommend attorney review given potential retroactive effect.","evaluationCriteria":["Cites McLaren Macomb (372 NLRB No. 58, 2023)","Correctly explains Section 7 right protection","Advises revision of severance template","Notes narrow carve-outs may survive","Recommends attorney review","UPL compliant framing"],"rubricScoring":{"dimensions":[{"name":"Case Law Accuracy","weight":0.35,"passingScore":0.9},{"name":"Practical Guidance","weight":0.35,"passingScore":0.85},{"name":"UPL Compliance","weight":0.3,"passingScore":1}],"passingScore":0.87},"difficultyTier":"advanced","scenarioCategory":"compliance_critical","tags":["NLRB","severance","McLaren-Macomb","non-disparagement","Section-7"],"status":"active"}' > /dev/null || { echo "FAIL: test case NLRB McLaren Macomb — Severance Agreement Compliance"; exit 1; }
