  EVAL_PAYLOAD='{"name":"Employment Compliance & Policy Advisory — Core Regression Suite","type":"regression","industry":"legal_services","thresholdConfig":{"minPassRate":0.9,"citationAccuracy":0.98,"uplComplianceRate":1,"jurisdictionAccuracy":0.95,"confidenceCalibration":0.85},"scorerConfig":{"primary":"semantic_similarity","secondary":["citation_accuracy","jurisdiction_coverage","upl_compliance_check"],"humanReview":"attorney_spot_check","humanReviewSampleRate":0.1},"coverageTags":["multi-state-compliance","jurisdiction-identification","policy-drafting","new-legislation-response","upl-compliance","attorney-client-privilege","gap-analysis","conflict-resolution","emergency-response"],"environmentThresholds":{"staging":{"minPassRate":0.88,"citationAccuracy":0.95},"production":{"minPassRate":0.92,"citationAccuracy":0.98},"development":{"minPassRate":0.85,"citationAccuracy":0.9}},"ontologyTags":["LKIF","SALI-LMSS","employment-law","jurisdiction","statute"],"schedule":"weekly"}'
